proof_block:
// The synthetic ensures has the shape
//     H ==> det_resolve_iommu_table_mapping_equal(r1, r2)
// where H is the conjunction of the original ensures applied to r1 and r2.
//
// The previous attempt asserted parts of H (e.g. `contains_va == r1.is_Some()`)
// at the top of the body — those failed because H is *not* a hypothesis at the
// top of the synthetic proof body; it is only the antecedent of the
// implication we must establish.
//
// The fix here: bind H to a local boolean and case-split on it. Inside the
// `if h { ... }` branch every conjunct of H is true in the proof context, so
// the helper lemma's `requires` are discharged and it yields
// det_resolve_iommu_table_mapping_equal(r1, r2) — exactly the consequent.
let m = self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k();
let contains_va = m.dom().contains(va);

let h: bool = {
    &&& (contains_va == (r1 is Some))
    &&& (r1 is Some ==> contains_va
            && m[va] == page_entry_to_map_entry(&r1.unwrap()))
    &&& (contains_va == (r2 is Some))
    &&& (r2 is Some ==> contains_va
            && m[va] == page_entry_to_map_entry(&r2.unwrap()))
};

if h {
    // Every conjunct of H is available here — feed them to the helper lemma.
    lemma_resolve_iommu_table_mapping_det_equal(self_, ioid, va, r1, r2);
    assert(det_resolve_iommu_table_mapping_equal(r1, r2));
}
// After the `if h { ... }`, Verus knows
// `h ==> det_resolve_iommu_table_mapping_equal(r1, r2)`. `h` is exactly the
// antecedent of the synthetic ensures, so this discharges it.

helper_lemmas:
// Helper functional-uniqueness lemma. The antecedent of the synthetic
// `det_<f>` ensures (i.e. the original ensures of resolve_iommu_table_mapping
// applied to both r1 and r2) is moved into `requires` here so that every
// assertion in the body has those pinning facts available as real
// hypotheses — which is exactly what the previous attempt got wrong: it
// asserted those facts at the top of the synthetic body, where they are
// only the antecedent of an implication and so are NOT yet in scope.
proof fn lemma_resolve_iommu_table_mapping_det_equal(
    self_: &MemoryManager,
    ioid: IOid,
    va: VAddr,
    r1: Option<PageEntry>,
    r2: Option<PageEntry>,
)
    requires
        self_.wf(),
        self_.ioid_active(ioid),
        va_4k_valid(va),
        self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k().dom().contains(va)
            == (r1 is Some),
        r1 is Some ==> self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k().dom().contains(va)
            && self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k()[va]
                == page_entry_to_map_entry(&r1.unwrap()),
        self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k().dom().contains(va)
            == (r2 is Some),
        r2 is Some ==> self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k().dom().contains(va)
            && self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k()[va]
                == page_entry_to_map_entry(&r2.unwrap()),
    ensures
        det_resolve_iommu_table_mapping_equal(r1, r2),
{
    // Bind the shared spec call so z3 sees a single term for both r1 and r2.
    let m = self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k();
    let contains_va = m.dom().contains(va);

    // Both is_Some-discriminators are pinned to contains_va, so they agree.
    assert(contains_va == (r1 is Some));
    assert(contains_va == (r2 is Some));
    assert((r1 is Some) == (r2 is Some));

    if r1 is Some {
        assert(r2 is Some);
        assert(contains_va);
        // m[va] is pinned to the *same* MapEntry by both ensures conjuncts,
        // so the two projections are forced equal.
        assert(m[va] == page_entry_to_map_entry(&r1.unwrap()));
        assert(m[va] == page_entry_to_map_entry(&r2.unwrap()));
        assert(page_entry_to_map_entry(&r1.unwrap())
            == page_entry_to_map_entry(&r2.unwrap()));

        // spec_page_entry_to_map_entry is `open`, so MapEntry equality
        // unfolds to field equality on { addr, write, execute_disable }.
        assert(spec_page_entry_to_map_entry(&r1.unwrap())
            =~= spec_page_entry_to_map_entry(&r2.unwrap()));
        assert(r1.unwrap().addr == r2.unwrap().addr);
        assert(r1.unwrap().perm.write == r2.unwrap().perm.write);
        assert(r1.unwrap().perm.execute_disable
            == r2.unwrap().perm.execute_disable);

        // PageEntryView is `pub struct { addr, perm }` with `addr` already
        // forced equal above. Bridge the remaining perm-fields by view
        // extensionality (`=~=`).
        assert((r1->Some_0).view() =~= (r2->Some_0).view());
        assert((r1->Some_0).view() == (r2->Some_0).view());
    }
}
